#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=3000005;
int n,m,cnt,ans,nxt[N][30],cnt2[N],dp[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int num=0;
		string s;
		cin>>s;
		reverse(s.begin(),s.end());
		for(int j=0;j<s.size();j++,num=nxt[num][s[j-1]-'a'])
		{
			int tmp=s[j]-'a';
			if(nxt[num][tmp]==0)
			{
				nxt[num][tmp]=++cnt;
			}
		}
		cnt2[num]++;
	}
	for(int i=cnt;i>-1;i--) 
	{
		dp[i]=cnt2[i];
//		cout<<i<<" "<<dp[i]<<"\n";
		int mx1=0,mx2=0;
		for(int j=0;j<26;j++)
		{
			if(cnt2[nxt[i][j]]==0) continue;
			if(dp[nxt[i][j]]-1>mx1)
			{
				mx2=mx1;
				mx1=dp[nxt[i][j]]-1;
			}
			else mx2=max(mx2,dp[nxt[i][j]]-1);
			dp[i]++;
		}
//		cout<<dp[i]<<" "<<mx1<<" "<<mx2<<'\n';
		dp[i]+=(mx1+mx2);
		ans=max(ans,dp[i]);
		dp[i]-=mx2;
	}
	cout<<ans;
	return 0;
}
